INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Activity Scheduling$q$, $q$Plan and track calls, meetings, and follow-up tasks tied to each opportunity.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Email Integration & Templates$q$, $q$Send and log outreach from within a record using reusable email templates.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$VoIP & Click-to-Call$q$, $q$Optional telephony integration for making and logging calls directly from the CRM.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Multi-Channel Lead Capture$q$, $q$Pulls leads in from website forms, live chat, and other Odoo-connected channels.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Sales Forecasting & Reporting$q$, $q$Dashboards for pipeline value, win rates, and rep performance over time.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Mobile App$q$, $q$iOS and Android apps for managing the pipeline and activities on the go.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Odoo Studio Customization$q$, $q$No-code tool for adding custom fields, views, and automations to the CRM module.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Genuinely free entry-level plan for a single app with unlimited users$q$, 0);
