INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Per-user pricing is generally more affordable than enterprise CRM suites$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Kanban pipeline and views are configurable without heavy technical work$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Large network of certified implementation partners for setup and support$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Full customization and workflow tuning has a real learning curve$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Feature depth in CRM-specific areas can trail dedicated sales-only platforms$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Advanced marketing automation and AI capabilities often require additional Odoo apps$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Support quality can vary depending on region and chosen implementation partner$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Teams that only need a CRM may find the wider Odoo ecosystem more than they need$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Is Odoo CRM free to use?$q$, $q$Yes. Odoo offers a free plan that includes one app, such as CRM, with unlimited users; paid Standard and Custom plans unlock the full app suite and additional functionality.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Does Odoo CRM integrate with other Odoo apps?$q$, $q$Yes. CRM shares a database with apps like Sales, Invoicing, Inventory, and Marketing, so opportunities can flow directly into quotes, orders, and invoices.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$How is Odoo CRM priced?$q$, $q$Beyond the free single-app plan, Odoo uses per-user monthly pricing across Standard and Custom tiers, typically billed annually, which unlock access to more apps and features.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Is there a mobile app for Odoo CRM?$q$, $q$Yes. Odoo provides mobile apps for iOS and Android so sales reps can manage their pipeline and activities away from a desktop.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Can I migrate data from another CRM into Odoo?$q$, $q$Yes. Odoo supports importing contacts and leads via CSV, and many teams work with an Odoo implementation partner for larger or more complex migrations.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Unifying Sales and Operations$q$, $q$Connecting won opportunities directly to sales orders, invoicing, and inventory so operations teams act on real-time pipeline data.$q$, $q$SMB distributors and manufacturers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Startup Sales Pipeline Management$q$, $q$Standing up a lightweight, no-cost pipeline to track early leads and deals before investing in a paid CRM.$q$, $q$Early-stage startups and small sales teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Multi-Company Sales Tracking$q$, $q$Managing separate pipelines and reporting across multiple legal entities or business units from one system.$q$, $q$Growing businesses with multiple companies or brands$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Replacing Spreadsheet-Based Lead Tracking$q$, $q$Moving lead and deal tracking out of shared spreadsheets into a structured pipeline with reminders and reporting.$q$, $q$Small teams outgrowing manual tracking methods$q$, 3);
