INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Standard$q$, $q$Around $24.90/user/month (billed annually)$q$, $q$monthly, billed annually$q$, $q$["Access to the full Odoo app suite","Workflow automation","Standard support","Multi-channel lead capture"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$Custom$q$, $q$Around $37.90/user/month (billed annually)$q$, $q$monthly, billed annually$q$, $q$["Everything in Standard","Multi-company support","External API access","Dedicated account support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Odoo CRM is the customer relationship management module inside Odoo, the Belgian-built suite of business applications that has grown since 2005 into one of the more widely deployed open-source-rooted ERP ecosystems. Rather than shipping as a standalone product, Odoo CRM lives alongside Sales, Invoicing, Inventory, Marketing, and dozens of other first-party apps, all sharing one database and one underlying data model.$q$, $q$At its core, the app gives sales teams a kanban-style pipeline for tracking leads and opportunities, tools for scoring and assigning incoming leads, activity scheduling to keep follow-ups on track, and reporting to forecast revenue. Because it sits inside the broader Odoo framework, a quote created in CRM can flow straight into a sales order, an invoice, and inventory reservations without re-entering data.$q$, $q$That integration is really the app's identity: it is less a best-of-breed CRM competing head-to-head with Salesforce or HubSpot on CRM-specific depth, and more the sales front-end of a modular business system. Companies already running or planning to run other Odoo apps tend to get the most value, since the CRM module effectively becomes free connective tissue between marketing, sales, and back-office execution.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$who-odoo-crm-is-for$q$, $q$Who Odoo CRM Is For$q$, 2, ARRAY[$q$Odoo CRM is best suited to small and mid-sized businesses that are already using, or seriously evaluating, Odoo for other parts of their operations, such as inventory, manufacturing, accounting, or e-commerce. For these companies, adding CRM is a natural extension rather than a new platform to learn from scratch.$q$, $q$It also fits sales teams that want their pipeline data to directly inform operational decisions, for example a distributor that needs sales forecasts to line up with purchasing, or a services business that wants a won opportunity to auto-generate a project and an invoice. Teams comfortable with some configuration, rather than a pure plug-and-play tool, will get the most out of it.$q$, $q$Budget-conscious growing businesses are another good match. The free single-app entry point lets a small sales team start tracking leads at no cost, and the per-user pricing on paid tiers tends to undercut enterprise CRM suites, making it attractive for companies that expect to add users or apps gradually as they scale.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large enterprises with complex, highly specialized sales operations, dedicated CRM administrators, and a preference for the deepest possible CRM-specific feature set may find Odoo CRM comparatively lighter than category leaders built solely around sales. Heavy reliance on a mature third-party marketplace of niche sales tools also favors platforms like Salesforce over Odoo's own app ecosystem.$q$, $q$Organizations that only need a CRM and have no intention of adopting other Odoo apps may not see the same value proposition, since much of the appeal comes from cross-app data flow. In that case, a purpose-built standalone CRM could be a simpler, more focused fit.$q$, $q$Non-technical teams that expect a fully guided, zero-configuration setup should also be cautious. Odoo's flexibility comes with a genuine configuration and customization surface, and getting field structures, automations, and views tuned to a specific sales process usually takes deliberate setup time or help from an implementation partner.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$The pipeline view is the centerpiece: a drag-and-drop kanban board for moving opportunities through configurable stages, alongside list, calendar, and reporting views of the same data. Lead scoring and assignment rules help route incoming leads to the right salesperson automatically, and activity scheduling keeps calls, meetings, and follow-up tasks visible so nothing slips through the pipeline unattended.$q$, $q$Built-in email integration lets reps log and send messages from within a record, using templates for common outreach, while optional VoIP and click-to-call integrations support phone-based sales workflows. Lead capture connects to website forms and live chat so inbound interest lands directly in the pipeline instead of a separate inbox.$q$, $q$On the analysis side, forecasting and reporting dashboards summarize pipeline value, win rates, and rep performance. A mobile app extends the pipeline to iOS and Android for reps working in the field, and Odoo Studio allows custom fields, views, and automations to be added without writing code, tailoring the module to a specific sales process.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dd5fd21d-0322-4d4a-b2d6-d37c26aaa320', $q$the-odoo-crm-experience$q$, $q$The Odoo CRM Experience$q$, 2, ARRAY[$q$Day to day, Odoo CRM feels clean and utilitarian rather than flashy: the kanban board is quick to scan, opportunities can be dragged between stages, and most record details are reachable in one or two clicks. The interface is consistent with the rest of Odoo, so once a user learns one app, the CRM module feels familiar rather than foreign.$q$, $q$Getting started usually means importing existing leads or contacts, defining pipeline stages that match the actual sales process, and setting up assignment or scoring rules. Odoo's large network of certified implementation partners exists specifically to help with this configuration step, and many growing teams lean on one rather than doing a full setup solo.$q$, $q$The overall experience rewards teams that treat Odoo as a connected system rather than a single tool: the CRM module on its own is solid but unremarkable, while its real strength shows up once quotes, invoices, projects, and inventory start updating automatically from pipeline activity, which is where the platform earns its value for the businesses it's built for.$q$]::text[], 4);
