INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('35eab88b-4ba3-4039-82ea-b4ff8bda85b1', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Single Sign-On$q$, $q$Lets users log in once to access all their connected applications, reducing password fatigue and login-related support requests.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Adaptive Multi-Factor Authentication$q$, $q$Applies risk-based authentication checks that factor in device, location, and behavior before granting or challenging access.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Universal Directory$q$, $q$Centralizes user profiles and attributes, syncing with existing directories and HR systems for a consistent source of identity data.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Lifecycle Management$q$, $q$Automates the provisioning and deprovisioning of accounts as employees join, change roles, or leave the organization.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Okta Integration Network$q$, $q$Provides a large catalog of pre-built connectors to common SaaS and on-premises applications for faster onboarding.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Okta Workflows$q$, $q$A no-code automation tool for building identity-related processes such as approvals, notifications, and access reviews.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$API Access Management$q$, $q$Secures APIs with OAuth-based authorization, allowing developers to control which clients and services can access backend resources.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Customer Identity Cloud$q$, $q$Built on Auth0, it gives developers embeddable login, social authentication, and user management for customer-facing applications.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Okta Verify and FastPass$q$, $q$Supports passwordless and phishing-resistant authentication methods to strengthen security while simplifying the login experience.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Extensive library of pre-built application integrations simplifies onboarding new tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Strong adaptive authentication and risk-based security controls$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3030433b-3418-43ac-aa59-beb69c92a481', $q$Centralized visibility and control over identity across the organization$q$, 2);
