INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$CRM & Helpdesk Integrations$q$, $q$Connect Olark to tools like Salesforce, HubSpot, and Zendesk to keep chat data in sync with sales and support records.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$Custom Chatbox Branding$q$, $q$Adjust colors, greeting text, and widget placement so the chat experience matches your site's look and feel.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$Transcripts & Reporting$q$, $q$Search past conversations and review reports on chat volume and agent performance over time.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$Google Analytics & Slack Integration$q$, $q$Sync chat events with Google Analytics and route notifications to Slack so teams stay informed without switching tools.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$API & Webhooks$q$, $q$Build custom integrations and data flows on top of Olark using its API and webhook support.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$Mobile-Friendly Chat Management$q$, $q$Respond to visitor chats from a mobile browser so agents aren't tied to a desktop to keep conversations moving.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$Fast, straightforward setup with minimal technical overhead$q$, 0);
