INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', $q$Lacks built-in ticketing beyond chat, often requiring a separate helpdesk tool$q$, 3);
