INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('96c3ecf0-fcaf-4131-91d0-08ec9da68acf', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Multi-Channel Automation Workflows$q$, $q$Build automated journeys that combine email, SMS, and web push in a single workflow, triggered by events like cart abandonment or completed purchases.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Pre-Built Workflow Templates$q$, $q$Launch common ecommerce automations, such as welcome series and post-purchase follow-ups, from ready-made templates instead of building logic from scratch.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Drag-and-Drop Email Editor$q$, $q$Design campaigns with a visual editor that includes ecommerce-specific content blocks like product pickers and discount codes.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$SMS Marketing$q$, $q$Send SMS campaigns and automated messages alongside email, using shared segmentation and contact data.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Signup Forms and Popups$q$, $q$Create customizable popups, landing pages, and signup forms to grow segmented subscriber lists directly from the storefront.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Customer Segmentation$q$, $q$Group contacts by purchase history, browsing behavior, and engagement to target campaigns more precisely.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Product Recommendations$q$, $q$Insert dynamic product recommendation blocks into emails based on browsing and purchase data.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Ecommerce Platform Integrations$q$, $q$Connect directly to platforms like Shopify, WooCommerce, and BigCommerce to sync orders, products, and customer data.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$A/B Testing$q$, $q$Test subject lines and campaign content to compare performance before sending to a full audience.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Revenue-Focused Reporting$q$, $q$Track campaign and automation performance with dashboards oriented around sales and revenue, not just opens and clicks.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Combines email, SMS, and web push in one automation builder$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Free plan makes it accessible for small or new online stores$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Deep integrations with major ecommerce platforms like Shopify and WooCommerce$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Pre-built workflow templates speed up automation setup$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Reporting is oriented around ecommerce revenue rather than generic engagement metrics$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Less suited to non-ecommerce businesses without storefront data$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Pricing scales with both contacts and SMS volume, which can add up for fast-growing lists$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Limited depth for complex B2B marketing needs like lead scoring or CRM workflows$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$SMS availability and features can vary by country$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Free plan has restricted sending limits and features compared to paid tiers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Does Omnisend offer a free plan?$q$, $q$Yes, Omnisend has a free plan with limited email sends and contacts, suitable for small stores getting started with email marketing.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Which ecommerce platforms does Omnisend integrate with?$q$, $q$Omnisend integrates with major platforms including Shopify, WooCommerce, BigCommerce, and Magento, syncing order and customer data for automation.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Can Omnisend send SMS messages as well as email?$q$, $q$Yes, Omnisend supports SMS marketing alongside email and web push, and these channels can be combined within a single automated workflow.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$How does Omnisend pricing work?$q$, $q$Omnisend prices its paid Standard and Pro plans based on contact list size and included SMS or email volume, in addition to the free plan for smaller lists.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Is Omnisend good for non-ecommerce businesses?$q$, $q$Omnisend is built around ecommerce data like orders and cart behavior, so businesses without an online store typically get less value from its core features.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Recovering Abandoned Carts$q$, $q$Automatically follow up with shoppers who add products to their cart but do not complete checkout, using timed email and SMS reminders.$q$, $q$Online store owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Welcoming New Subscribers$q$, $q$Trigger a multi-step welcome series when a new customer signs up through a popup or form, introducing the brand and encouraging a first purchase.$q$, $q$Ecommerce marketers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Driving Repeat Purchases$q$, $q$Use post-purchase automations and product recommendations to encourage customers to buy again based on past order history.$q$, $q$Retention marketing teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Managing Multiple Client Stores$q$, $q$Set up ecommerce-specific automations and reporting across several client storefronts using pre-built templates and platform integrations.$q$, $q$Marketing agencies$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Free$q$, $q$$0$q$, $q$monthly$q$, $q$["Limited monthly email sends","Signup forms and popups","Basic automation workflows","Limited contacts"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Standard$q$, $q$Starts around $16/month$q$, $q$monthly$q$, $q$["Increased email sending limits","SMS credits included","Pre-built automation workflows","Segmentation"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$Pro$q$, $q$Starts around $59/month$q$, $q$monthly$q$, $q$["Higher email and SMS limits","Advanced reporting","Web push notifications","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Omnisend is a marketing automation platform purpose-built for online stores, combining email, SMS, and web push into a single workflow builder rather than treating each channel as a separate product. The pitch is straightforward: ecommerce brands need to reach customers wherever they are, and Omnisend tries to make that possible without forcing teams to stitch together several point tools.$q$, $q$The platform connects directly to storefront platforms like Shopify, WooCommerce, and BigCommerce, pulling in order history, browsing behavior, and customer data so campaigns and automations can be triggered by real shopping activity rather than generic list criteria. That ecommerce-first data model is what differentiates it from broader email tools that were built for content publishers or B2B lead generation first and adapted for online retail later.$q$, $q$Out of the box, Omnisend ships with pre-built automation workflows for common ecommerce moments, such as cart abandonment, welcome series, and post-purchase follow-ups, along with a drag-and-drop editor for building emails, popups, and signup forms. The free plan makes it approachable for small stores just getting started, while the paid Standard and Pro tiers add SMS credits, push notifications, and more advanced automation and reporting for teams scaling their retention marketing.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$who-omnisend-is-for$q$, $q$Who Omnisend Is For$q$, 2, ARRAY[$q$Omnisend is aimed squarely at ecommerce merchants, from solo founders running a single Shopify store to mid-size retail brands with dedicated marketing teams. Its feature set and pricing structure are both organized around store size and contact volume rather than generic marketing use cases, which makes it a natural fit for anyone whose primary revenue channel is an online storefront.$q$, $q$Small and growing stores tend to appreciate the free plan and the pre-built automation templates, since they can get cart-abandonment and welcome emails running without designing workflows from scratch or hiring a specialist. Marketing teams at larger stores benefit from the ability to combine email, SMS, and push in a single automation, letting them build more coordinated campaigns without juggling separate SMS and push vendors.$q$, $q$Agencies and freelance marketers who manage multiple ecommerce clients also gravitate toward Omnisend because the platform-specific integrations reduce the setup work needed for each new store, and the reporting is oriented toward the metrics ecommerce clients actually care about, like revenue per campaign rather than just opens and clicks.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Businesses that are not selling products online may find Omnisend's feature set mismatched to their needs. Because so much of the platform is built around order data, cart events, and product recommendations, service businesses, SaaS companies, and content publishers are often better served by general-purpose email tools that are not optimized around a storefront.$q$, $q$Teams that need heavy B2B functionality, such as deep CRM integrations, complex lead scoring, or account-based marketing workflows, will likely find Omnisend too narrowly focused on the consumer purchase journey. Its automation logic and segmentation are strong for shopping behavior but were not designed for long B2B sales cycles.$q$, $q$Stores with very large contact lists or high SMS volume should also budget carefully, since Omnisend's paid tiers price by both contacts and message volume. Rapidly growing lists can push monthly costs up quickly, so brands anticipating fast scale should compare projected pricing against alternatives before committing.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the center of Omnisend is its automation workflow builder, which lets marketers create multi-step, multi-channel journeys triggered by events like site visits, cart abandonment, or completed purchases. Pre-built workflow templates cover the most common ecommerce scenarios, so teams can launch a functioning automation and then customize timing, content, and branching logic afterward.$q$, $q$The platform also includes a visual email editor with ecommerce-specific content blocks, such as product picker and discount code blocks, plus customizable signup forms and popups for building segmented lists. SMS and web push are managed from the same interface as email, so a single automation can fall back from one channel to another depending on customer preference or delivery status.$q$, $q$Segmentation tools let marketers group customers by purchase history, engagement, and predicted behavior, while built-in reporting ties campaign and automation performance back to revenue rather than just engagement metrics. A/B testing on subject lines and content, along with sales and performance dashboards, rounds out the toolkit for teams optimizing their retention marketing over time.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('902d8b1b-af39-4cdf-a2b7-db0c5672b059', $q$the-omnisend-experience$q$, $q$The Omnisend Experience$q$, 2, ARRAY[$q$Day-to-day, Omnisend feels purpose-built rather than general purpose. Connecting a store is typically the first step, and once that sync is in place, the dashboard surfaces store-specific metrics and suggested automations rather than a blank canvas, which shortens the path from signup to a live campaign.$q$, $q$Building emails and automations relies on drag-and-drop editing, and the workflow builder visualizes each branch and condition so it is easier to see how a customer might move through a welcome series or a win-back campaign. Teams that prefer building from pre-made templates rather than starting from scratch generally find the experience faster to get value from.$q$, $q$As stores grow, the experience becomes more about managing volume: more segments, more automations, more SMS credits, and closer attention to how contact and message pricing scales. Support and onboarding resources are geared toward ecommerce use cases specifically, which can make troubleshooting feel more relevant compared with generic marketing platforms, though teams with non-ecommerce needs may not find the same depth of guidance.$q$]::text[], 4);
