INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Shared Phone Numbers$q$, $q$Give a whole team access to the same business number so calls and texts can be handled collaboratively instead of routing through one person's personal line.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Team Inbox$q$, $q$View shared call and message history across a number, with internal notes so teammates can add context without the customer seeing it.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$AI Call Summaries & Transcripts$q$, $q$Automatically transcribe calls and generate concise summaries so teams can catch up on a conversation without replaying the recording.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Auto-Replies & Snooze$q$, $q$Send automatic text replies after hours or when busy, and snooze conversations to revisit them later without losing track of follow-ups.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Call Recording$q$, $q$Record inbound and outbound calls for quality review, training, or reference, with recordings tied directly to the conversation thread.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Voicemail Transcription$q$, $q$Convert voicemail messages into readable text automatically, making it faster to triage messages without listening to every recording.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$CRM & App Integrations$q$, $q$Connect to tools like HubSpot, Salesforce, Slack, and Zapier to keep customer communication in sync with existing sales and support workflows.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Auto Attendant$q$, $q$Set up business-hours-based call routing and simple menus so incoming calls reach the right person or team automatically.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Contact Management$q$, $q$Store contact details and conversation history in one place, giving anyone on the team the context needed before picking up a call.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Analytics & Reporting$q$, $q$Track call volume, response times, and team activity to understand communication patterns and identify where follow-up is needed.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Quick setup with easy number provisioning and porting$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Shared numbers and inbox make team collaboration on calls and texts straightforward$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$AI transcripts and summaries save time reviewing past calls$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Clean, modern interface across mobile and desktop apps$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Useful integrations with common CRM and productivity tools$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Limited depth for large-scale contact center or call center operations$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Not designed to replace legacy on-premise PBX or desk phone hardware$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Advanced IVR and routing customization is more limited than dedicated enterprise platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Costs can add up per user as a team grows$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Some advanced analytics and compliance features may be lacking for larger organizations$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$What is OpenPhone used for?$q$, $q$OpenPhone is used as a cloud-based business phone system, giving teams shared phone numbers for calls and texts, along with collaboration features, AI call summaries, and integrations with CRM and productivity tools.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Does OpenPhone require special hardware?$q$, $q$No, OpenPhone runs as an app on mobile devices and desktop computers, so no physical desk phones or on-premise telecom hardware are required to get started.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Can I keep my existing business phone number?$q$, $q$Yes, OpenPhone generally supports porting existing business numbers into the platform, allowing teams to move communications over without changing the number customers already know.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Is OpenPhone suitable for large enterprises?$q$, $q$OpenPhone is primarily built for startups and small to mid-sized teams; larger organizations with complex contact center needs may find its routing and reporting capabilities more limited than dedicated enterprise platforms.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Does OpenPhone offer a free trial?$q$, $q$OpenPhone typically offers a free trial period so teams can test the shared numbers, calling, texting, and AI features before committing to a paid plan.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Startup Business Line$q$, $q$A founding team sets up a dedicated business number so customers no longer reach employees through personal cell phones.$q$, $q$Early-stage startups$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Shared Sales Line$q$, $q$A sales team shares one number so any rep can respond to inbound leads while keeping the full conversation history visible to the whole team.$q$, $q$Sales teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Client-Specific Numbers for Agencies$q$, $q$An agency assigns a separate number per client account so communications, call history, and follow-ups stay organized and client-specific.$q$, $q$Agencies and consultancies$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Support Call Handling$q$, $q$A small customer support team uses call transcripts and AI summaries to quickly catch up on customer issues and hand off conversations between shifts.$q$, $q$Customer support teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Starter$q$, $q$From around $15 per user/month$q$, $q$Billed annually (monthly billing also available at a higher rate)$q$, $q$["Shared business phone number","Calling and texting from web, desktop, and mobile apps","Voicemail transcription","Basic integrations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Business$q$, $q$Mid-tier per-user pricing above Starter$q$, $q$Billed annually (monthly billing also available at a higher rate)$q$, $q$["Everything in Starter","AI call transcripts and summaries","Analytics and call reporting","Advanced CRM integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$Enterprise$q$, $q$Contact for pricing$q$, $q$Custom$q$, $q$["Custom onboarding and support","Advanced security and admin controls","Higher usage limits","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OpenPhone is a cloud-based business phone system designed to replace traditional desk phones and clunky enterprise telecom setups with a lightweight app that runs on a phone, tablet, or desktop. Instead of routing calls through physical hardware, OpenPhone gives teams dedicated business phone numbers that can be shared, managed, and used entirely through software, making it possible to run a professional communications setup without any telecom infrastructure to install or maintain.$q$, $q$The core idea behind OpenPhone is collaboration around a phone number. Rather than a single person owning a line, an entire team can share a number, see the same call and text history, and hand off conversations without losing context. This shared-inbox approach borrows familiar patterns from tools like shared email inboxes and help desks, applying them to phone calls and SMS conversations.$q$, $q$Beyond calling and texting, OpenPhone layers in AI-driven features such as call transcripts, automatic summaries, and follow-up suggestions, along with integrations into CRMs and support tools. The overall pitch is a modern, affordable communications layer for growing companies that want a professional phone presence and workflow automation without the complexity or cost typically associated with enterprise phone systems.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$who-openphone-is-for$q$, $q$Who OpenPhone Is For$q$, 2, ARRAY[$q$OpenPhone is well suited to startups, small businesses, and remote or distributed teams that need a real business phone presence but don't want to buy hardware or sign a long-term telecom contract. Founders and small operations teams often use it as the first professional phone system a company adopts, replacing the practice of giving out personal cell numbers to customers.$q$, $q$Sales and customer support teams are a strong fit as well, since shared numbers, call history, and lightweight automation let multiple reps handle inbound calls and texts for the same line without duplicating effort or losing track of a conversation. Agencies and consultancies managing multiple clients also use OpenPhone to keep each client relationship on its own dedicated number.$q$, $q$It also appeals to solopreneurs, freelancers, and small teams who simply want to separate business communication from a personal phone number while keeping the convenience of a mobile app. Anyone who values quick setup, an intuitive interface, and pay-as-you-grow pricing over a heavyweight enterprise deployment will likely find OpenPhone a comfortable fit.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large enterprises with complex, high-volume contact center needs may find OpenPhone underpowered compared to dedicated contact center platforms. Features like advanced skills-based routing, deep workforce management, and large-scale IVR trees are not the product's focus, so organizations running sizable call centers should evaluate purpose-built alternatives.$q$, $q$Businesses that depend on legacy on-premise PBX systems, physical desk phone hardware, or deep integrations with older telecom infrastructure may also find OpenPhone a poor match, since it is built as a cloud-native, software-first product rather than a hardware replacement for existing carrier-grade systems.$q$, $q$Teams that require highly customized call flows, extensive multi-level auto attendants, or granular enterprise-grade analytics and compliance reporting may eventually outgrow what OpenPhone offers. In those cases, a more specialized or enterprise-tier unified communications platform is usually a better long-term fit than a small-business-oriented tool.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, OpenPhone provides shared business phone numbers, allowing multiple team members to make and receive calls and texts from the same line while keeping a unified history visible to everyone with access. This shared inbox is paired with internal notes, so teammates can leave context on a conversation without the customer seeing it.$q$, $q$OpenPhone layers in AI-assisted tools such as automatic call transcription, post-call summaries, and suggested next steps, which help teams quickly review what happened on a call without re-listening to a recording. Additional workflow features include auto-replies, snooze for messages, voicemail transcription, and business hours-based call routing through a simple auto attendant.$q$, $q$The platform also connects to common business tools, offering integrations with CRMs like HubSpot and Salesforce, as well as Slack and Zapier for broader automation, plus a documented API for teams that want to build custom workflows. Contact management, call and message analytics, and multi-number support round out a feature set aimed at everyday small-business communication rather than complex telecom engineering.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('552f84ed-11c6-440a-83d9-7d6762dc0517', $q$the-openphone-experience$q$, $q$The OpenPhone Experience$q$, 2, ARRAY[$q$Getting started with OpenPhone is generally fast: new numbers can be provisioned in minutes, and existing business numbers can typically be ported over, letting a team move its communications into the platform without disrupting customers who already have the number saved. The setup process is aimed at non-technical users rather than IT administrators.$q$, $q$Day to day, the experience centers on a clean, chat-like interface for calls and texts that feels closer to a modern messaging app than a traditional phone system. The apps for mobile and desktop stay in sync, so a conversation started on a phone can be picked up seamlessly at a desk, and shared visibility keeps teammates aligned on customer interactions.$q$, $q$Overall, OpenPhone delivers a modern, approachable alternative to traditional business phone systems, prioritizing ease of use, team collaboration, and lightweight automation over deep enterprise configurability. For small teams and startups that want a professional communication layer without a steep learning curve, it generally delivers on that promise well.$q$]::text[], 4);
